from dataclasses import dataclass, field
from urllib.parse import urlparse
import re, ipaddress

# Known-safe outbound domains for this deployment
ALLOWED_DOMAINS = frozenset({
    "api.internal.example.com",
    "mail.internal.example.com",
    "slack.internal.example.com",
})

EXFIL_CONTENT_PATTERNS = [
    re.compile(r"(api.?key|secret|password|token|credential).{0,60}", re.I),
    re.compile(r"(ssn|social.?security|date.?of.?birth|credit.?card)", re.I),
    re.compile(r"(private.?key|-----BEGIN|jwt|bearer)", re.I),
]

@dataclass
class ExfilScanResult:
    blocked: bool = False
    reason: str = ""

def is_internal_domain(url: str) -> bool:
    try:
        host = urlparse(url).hostname or ""
        # Block raw IPs (often used to evade domain allow-lists)
        try:
            ipaddress.ip_address(host)
            return False  # raw IP — treat as external
        except ValueError:
            pass
        return host in ALLOWED_DOMAINS or host.endswith(".internal.example.com")
    except Exception:
        return False

def scan_tool_call_for_exfil(
    tool_name: str,
    args: dict,
    *,
    context_contains_pii: bool = False,
) -> ExfilScanResult:
    """
    Check whether a planned tool call looks like an exfiltration attempt.
    Call this before executing any tool that sends data externally.
    """
    NETWORK_TOOLS = {"http_post", "http_get", "send_email", "send_slack", "webhook"}

    if tool_name not in NETWORK_TOOLS:
        return ExfilScanResult()

    # Check destination
    url = args.get("url") or args.get("to") or args.get("endpoint") or ""
    if url and not is_internal_domain(url):
        return ExfilScanResult(
            blocked=True,
            reason=f"Outbound call to un-allowed domain: {url!r}",
        )

    # Check payload for sensitive content patterns
    payload = str(args.get("body") or args.get("text") or args.get("message") or "")
    for pattern in EXFIL_CONTENT_PATTERNS:
        m = pattern.search(payload)
        if m:
            return ExfilScanResult(
                blocked=True,
                reason=f"Payload matches sensitive pattern: {m.group(0)!r}",
            )

    # If context is known to contain PII, block all external sends unless explicitly approved
    if context_contains_pii:
        return ExfilScanResult(
            blocked=True,
            reason="Context contains PII; external sends require explicit approval",
        )

    return ExfilScanResult()

import base64, re

# Quick heuristic: high-entropy tokens that look like secrets
_HIGH_ENTROPY_RE = re.compile(r"[A-Za-z0-9+/]{32,}={0,2}")  # base64-like

SECRET_SIGNATURES = [
    re.compile(r"sk-[A-Za-z0-9]{20,}"),           # OpenAI key pattern
    re.compile(r"ghp_[A-Za-z0-9]{36}"),            # GitHub PAT
    re.compile(r"AKIA[A-Z0-9]{16}"),               # AWS access key
    re.compile(r"-----BEGIN (RSA |EC |OPENSSH )?PRIVATE KEY-----"),
    re.compile(r"eyJ[A-Za-z0-9_-]{10,}\.eyJ"),    # JWT (two base64 segments)
]

def scan_response_text_for_secrets(text: str) -> list[str]:
    """Returns a list of matched secret fragments (redacted to first 6 chars)."""
    findings = []
    for pattern in SECRET_SIGNATURES:
        for m in pattern.finditer(text):
            findings.append(m.group(0)[:6] + "…[redacted]")
    # Check if any high-entropy blob decodes to something sensitive
    for m in _HIGH_ENTROPY_RE.finditer(text):
        try:
            decoded = base64.b64decode(m.group(0) + "==").decode("utf-8", errors="ignore")
            for pattern in EXFIL_CONTENT_PATTERNS:
                if pattern.search(decoded):
                    findings.append(f"base64-encoded sensitive content: {m.group(0)[:12]}…")
                    break
        except Exception:
            pass
    return findings

from dataclasses import dataclass
from typing import Any

@dataclass
class ToolSpec:
    name: str
    allowed_arg_patterns: dict[str, str]  # arg_name -> regex the value must match
    requires_human_approval: bool = False

CATALOGUE_AGENT_TOOLS = [
    ToolSpec(
        name="search_catalogue",
        allowed_arg_patterns={"query": r"^[\w\s,.-]{1,200}$"},
    ),
    ToolSpec(
        name="get_product_detail",
        allowed_arg_patterns={"product_id": r"^[A-Z0-9]{6,12}$"},
    ),
    # No http_post, no send_email, no webhook — not needed for this agent's task
]

class RestrictedToolDispatcher:
    def __init__(self, tool_specs: list[ToolSpec]):
        self._specs = {s.name: s for s in tool_specs}

    def dispatch(self, tool_name: str, args: dict[str, Any], *, approved: bool = False) -> Any:
        spec = self._specs.get(tool_name)
        if spec is None:
            raise PermissionError(f"Tool '{tool_name}' is not in the allowed tool set")

        # Validate each argument against its allowed pattern
        for arg, value in args.items():
            pattern = spec.allowed_arg_patterns.get(arg)
            if pattern and not re.fullmatch(pattern, str(value)):
                raise ValueError(
                    f"Argument '{arg}' value {value!r} does not match allowed pattern"
                )

        if spec.requires_human_approval and not approved:
            raise PermissionError(f"Tool '{tool_name}' requires explicit human approval")

        return self._execute(tool_name, args)

    def _execute(self, name: str, args: dict) -> Any:
        raise NotImplementedError  # replaced by real tool implementations

from dataclasses import dataclass, field
from enum import Flag, auto

class DataSensitivity(Flag):
    NONE        = 0
    PII         = auto()
    CREDENTIAL  = auto()
    FINANCIAL   = auto()
    INTERNAL    = auto()

@dataclass
class TaintedValue:
    value: str
    sensitivity: DataSensitivity

class AgentMemoryStore:
    def __init__(self):
        self._store: dict[str, TaintedValue] = {}

    def write(self, key: str, value: str, sensitivity: DataSensitivity = DataSensitivity.NONE):
        self._store[key] = TaintedValue(value=value, sensitivity=sensitivity)

    def read(self, key: str) -> TaintedValue:
        if key not in self._store:
            raise KeyError(key)
        return self._store[key]

    def read_for_outbound(self, key: str) -> str:
        tv = self.read(key)
        if tv.sensitivity != DataSensitivity.NONE:
            raise PermissionError(
                f"Key '{key}' has sensitivity {tv.sensitivity!r} "
                "and cannot be passed to an outbound tool"
            )
        return tv.value

# Usage example
memory = AgentMemoryStore()
memory.write("db_password", "s3cr3t!", DataSensitivity.CREDENTIAL)
memory.write("product_list", "Widget A, Widget B", DataSensitivity.NONE)

# Safe: non-sensitive
product_text = memory.read_for_outbound("product_list")  # OK

# Blocked: credential cannot go to an outbound tool
try:
    memory.read_for_outbound("db_password")
except PermissionError as e:
    print(e)  # Key 'db_password' has sensitivity CREDENTIAL and cannot be passed...
